+.feedback {
+  width: 100%;
+  height: 672px;             
+  box-sizing: border-box;
+  
+  background-image: url('./image_Feedback/feedback-bg.png');
+  background-size: cover;
+  background-position: center;
+  background-repeat: no-repeat;
+  
+  display: flex;
+  justify-content: center;
+}
+
+.feedback__container {
+  width: 100%;
+  max-width: 1440px;        
+  height: 100%;
+  box-sizing: border-box;
+  position: relative;       
+  
+  display: flex;
+  align-items: flex-start;  /* Прижимаем контент к верху для точного отсчета margin */
+}
+
+/* Начинаем описывать саму карточку формы */
+.formCard {
+  box-sizing: border-box;
+  
+  /* Точные макетные отступы от краев контейнера 1440px */
+  margin-top: 54px;         /* Округлили 53.56px */
+  margin-left: 222px;       /* Строго по макету */
+  
+  /* Нижний padding-bottom секции закроется за счет общей высоты 603px */
+}

