+/* Возвращаем полную макетную высоту всей секции */
+.feedback {
+  width: 100%;
+  height: 672px;            /* СТРОГО ВОЗВРАЩАЕМ 672px по макету */
+  box-sizing: border-box;
+  
+  background-image: url('./image_Feedback/feedback-bg.jpg');
+  background-size: cover;
+  background-position: center;
+  background-repeat: no-repeat;
+  
+  display: flex;
+  justify-content: center;
+}
+
+.feedback__container {
+  width: 100%;
+  max-width: 1440px;        
+  height: 100%;
+  box-sizing: border-box;
+  position: relative;       
+  
+  display: flex;
+  align-items: flex-start;  /* Оставляем для точного расчета верхнего margin карточки */
+}
+
+/* Переносим жесткие макетные размеры на саму темную карточку */
+.formCard {
+  width: 448px;             /* Жесткая ширина карточки Rectangle 47 из панели Pixso */
+  height: 603px;            /* Жесткая высота карточки Rectangle 47 из панели Pixso */
+  box-sizing: border-box;
+  
+  /* Точное позиционирование карточки по розовым маркерам макета */
+  margin-top: 54px;         /* Отступ сверху 53.56px (округлили до 54) */
+  margin-left: 222px;       /* Отступ слева строго по макету */
+  
+  /* Цвета и обводка из панели справа (Цвет: темно-серый #1C1D1E, Обводка: оранжевый #FF7A00) */
+  background-color: #1c1d1e;
+  border: 4px solid #ff7a00; /* Проверим толщину обводки, пока заложим стандартные 4px как на прошлых блоках */
+}

